import os
import sys
import boto3
from botocore.exceptions import ClientError, NoCredentialsError, PartialCredentialsError

BUCKET_NAME = "demo-bucket"

# Provide credentials via environment variables at runtime:
#   AWS_ACCESS_KEY_ID=... AWS_SECRET_ACCESS_KEY=... python list_s3_files.py
# Or use a shared credentials file/profile.
ACCESS_KEY_ENV = "AWS_ACCESS_KEY_ID"
SECRET_KEY_ENV = "AWS_SECRET_ACCESS_KEY"
SESSION_TOKEN_ENV = "AWS_SESSION_TOKEN"
REGION_ENV = "AWS_DEFAULT_REGION"

def make_s3_client():
    access_key = os.environ.get(ACCESS_KEY_ENV)
    secret_key = os.environ.get(SECRET_KEY_ENV)
    session_token = os.environ.get(SESSION_TOKEN_ENV)
    region = os.environ.get(REGION_ENV)

    if access_key and secret_key:
        kwargs = {
            "aws_access_key_id": access_key,
            "aws_secret_access_key": secret_key,
        }
        if session_token:
            kwargs["aws_session_token"] = session_token
        if region:
            kwargs["region_name"] = region
        return boto3.client("s3", **kwargs)

    return boto3.client("s3")

def list_all_objects(bucket):
    s3 = make_s3_client()
    paginator = s3.get_paginator("list_objects_v2")

    found_any = False
    for page in paginator.paginate(Bucket=bucket):
        for obj in page.get("Contents", []):
            print(obj["Key"])
            found_any = True

    if not found_any:
        print("(no objects found)")

